var raw = $input.item.json;
var payload = raw.body || raw.json || raw;
var email = payload.email;
var userId = payload.userId;
var tenantId = payload.tenantId;
var resetToken = payload.resetToken;

if (!email) throw new Error('email manquant');
if (!resetToken) throw new Error('resetToken manquant');

var baseUrl = 'https://demo.talosprimes.com';
var resetLink = baseUrl + '/reset-password?token=' + encodeURIComponent(resetToken);

var htmlBody = '<!DOCTYPE html><html><head><meta charset="utf-8"></head><body style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto;padding:20px;">' +
  '<div style="text-align:center;margin-bottom:30px;">' +
  '<h1 style="color:#4F46E5;">TalosPrimes</h1>' +
  '</div>' +
  '<h2 style="color:#1F2937;">Réinitialisation de votre mot de passe</h2>' +
  '<p style="color:#4B5563;line-height:1.6;">Vous avez demandé la réinitialisation de votre mot de passe. Cliquez sur le bouton ci-dessous pour choisir un nouveau mot de passe :</p>' +
  '<div style="text-align:center;margin:30px 0;">' +
  '<a href="' + resetLink + '" style="background-color:#4F46E5;color:#ffffff;padding:14px 28px;text-decoration:none;border-radius:8px;font-weight:bold;display:inline-block;">Réinitialiser mon mot de passe</a>' +
  '</div>' +
  '<p style="color:#6B7280;font-size:14px;">Ce lien est valable 15 minutes. Si vous n\'avez pas demandé cette réinitialisation, ignorez cet email.</p>' +
  '<hr style="border:none;border-top:1px solid #E5E7EB;margin:30px 0;">' +
  '<p style="color:#9CA3AF;font-size:12px;text-align:center;">TalosPrimes — Plateforme de gestion d\'entreprise automatisée</p>' +
  '</body></html>';

var textBody = 'Réinitialisation de votre mot de passe TalosPrimes\n\n' +
  'Cliquez sur ce lien pour réinitialiser votre mot de passe :\n' + resetLink + '\n\n' +
  'Ce lien est valable 15 minutes.\nSi vous n\'avez pas demandé cette réinitialisation, ignorez cet email.';

return [{
  json: {
    email: email,
    userId: userId,
    tenantId: tenantId,
    resetLink: resetLink,
    subject: 'Réinitialisation de votre mot de passe - TalosPrimes',
    htmlBody: htmlBody,
    textBody: textBody
  }
}];
